// SPDX-License-Identifier: MIT
//
// ReleaseSafe diagnostic test — run on OHOS to verify safety checks catch UAF
//
// Tests:
//   1. Load ReleaseSafe libopentui.so — should load without error
//   2. Create EditBuffer, insertText with varying string lengths — checks for safety check panics
//   3. Polling API smoke test — verifies pollEvent/readEventName/readEventData work
//   4. Typing stress — simulates the crash trigger (6-12 chars typed repeatedly)
//
// Usage (on OHOS):
//   cd ~ && node-22 /data/.../test-releasesafe.mjs
//
// Expected output:
//   - All PASS: ReleaseSafe binary is working correctly
//   - Zig panic with file:line → ReleaseSafe caught a UAF, report the location
//   - SIGSEGV (caught by sigcatch) → crash still occurs, need further analysis

import { createRequire } from "node:module"
import * as fs from "node:fs"
import { resolve } from "node:path"

const _req = createRequire(import.meta.url)
const HERE = process.cwd()

// Try loading koffi — supports both bundled and system-installed
let koffi
try {
  koffi = _req("@koromix/koffi-openharmony-arm64")
} catch {
  koffi = _req("koffi")
}

const LIB_PATH = resolve(HERE, "libopentui.so")
const SIGCATCH_PATH = resolve(HERE, "sigcatch.so")

let pass = 0
let fail = 0
let safetyPanic = false

function assert(ok, msg) {
  if (ok) {
    fs.writeSync(2, `  PASS: ${msg}\n`)
    pass++
  } else {
    fs.writeSync(2, `  FAIL: ${msg}\n`)
    fail++
  }
}

function header(title) {
  fs.writeSync(2, `\n=== ${title} ===\n`)
}

// ============================================================
// Phase 0: Install sigcatch crash handler (if sigcatch.so exists)
// ============================================================
header("Phase 0: sigcatch handler")

if (fs.existsSync(SIGCATCH_PATH)) {
  try {
    const sigcatch = koffi.load(SIGCATCH_PATH)
    const logPath = (process.env.HOME || "/tmp") + "/opencode-crash.log"
    sigcatch.func("set_log_path", "int", ["string", "int"])(logPath, logPath.length)
    sigcatch.func("install_handler", "void", [])()
    assert(true, `sigcatch handler installed, crash log → ${logPath}`)
  } catch (e) {
    assert(false, `sigcatch load/install failed: ${e.message}`)
  }
} else {
  fs.writeSync(2, "  INFO: sigcatch.so not found alongside libopentui.so — crash handler skipped\n")
}

// ============================================================
// Phase 1: Load ReleaseSafe lib and verify symbols
// ============================================================
header("Phase 1: Load ReleaseSafe lib")

let lib
try {
  lib = koffi.load(LIB_PATH)
  assert(true, `libopentui.so loaded from ${LIB_PATH}`)
} catch (e) {
  assert(false, `load failed: ${e.message}`)
  process.exit(1)
}

// Check polling API symbols
const pollEvent = lib.func("pollEvent", "bool", [])
const setUsePolling = lib.func("setUsePolling", "void", ["bool"])
const readEventName = lib.func("readEventName", "uint64", ["void*", "uint64"])
const readEventData = lib.func("readEventData", "uint64", ["void*", "uint64"])
const disableEvents = lib.func("disableEvents", "void", ["bool"])

assert(typeof pollEvent === "function", "pollEvent symbol resolved")
assert(typeof setUsePolling === "function", "setUsePolling symbol resolved")
assert(typeof readEventName === "function", "readEventName symbol resolved")
assert(typeof readEventData === "function", "readEventData symbol resolved")
assert(typeof disableEvents === "function", "disableEvents symbol resolved")

// Verify polling is enabled by default
const pollingInitial = pollEvent()
assert(pollingInitial === false, `pollEvent() returns ${pollingInitial} (expected false with no events)`)

// ============================================================
// Phase 2: Create EditBuffer and simulate typing
// ============================================================
header("Phase 2: EditBuffer typing test")

const createEditBuffer = lib.func("createEditBuffer", "void*", ["uint8"])
const editBufferInsertText = lib.func("editBufferInsertText", "void", ["void*", "string"])
const destroyEditBuffer = lib.func("destroyEditBuffer", "void", ["void*"])
const editBufferGetCursor = lib.func("editBufferGetCursor", "void", ["void*", "uint32*", "uint32*"])
const editBufferSetCursor = lib.func("editBufferSetCursor", "void", ["void*", "uint32", "uint32"])
const editBufferGetTextBuffer = lib.func("editBufferGetTextBuffer", "void*", ["void*"])

const eb = createEditBuffer(0) // widthMethod=0 (wcwidth)
assert(eb !== null && eb !== undefined, "createEditBuffer returned non-null pointer")

// Try to load sigcatch to catch panics
// Note: Zig safety check panics call SYS_write(2, msg) then SYS_exit
// This will appear as stderr output before process exit

const TEST_STRINGS = [
  "a",        // 1 char
  "hello",    // 5 chars
  "abcdefgh", // 8 chars — within crash range
  "ijklmnopqrstuv", // 14 chars — past typical crash threshold
  "123456",   // 6 chars
  "test input typing", // 16 chars
]

header("Phase 2a: Single insertText calls")
for (const s of TEST_STRINGS) {
  try {
    editBufferInsertText(eb, s)
    assert(true, `insertText("${s}") (len=${s.length}) completed without panic`)
  } catch (e) {
    // koffi might throw on signal/SIGABRT from Zig panic
    assert(false, `insertText("${s}") threw: ${e.message}`)
    safetyPanic = true
  }
}

// Verify cursor moved (text was actually inserted)
const rowBuf = Buffer.alloc(4)
const colBuf = Buffer.alloc(4)
editBufferGetCursor(eb, rowBuf, colBuf)
const row = rowBuf.readUInt32LE(0)
const col = colBuf.readUInt32LE(0)
assert(row >= 0, `cursor row=${row} (valid)`)
assert(col > 0, `cursor col=${col} > 0 (text was inserted)`)

// ============================================================
// Phase 3: Typing stress — simulate 6-12 char typing repeatedly
// ============================================================
header("Phase 3: Typing stress (the crash trigger)")

// Reset cursor to start
editBufferSetCursor(eb, 0, 0)

const STRESS_COUNT = 100
let stressPanics = 0

// Typing pattern that triggers the crash: 6-12 characters, Backspace, repeat
const CHAR_SETS = [
  "abc", "def", "ghi", "jkl", "mno", "pqr", "stu", "vwx", "yz",
  "123", "456", "789", "0!@", "#$%", "^&*", "()_", "+-=", "[]{}",
]

for (let cycle = 0; cycle < STRESS_COUNT; cycle++) {
  // Pick a random 6-12 char string
  const setIdx = cycle % CHAR_SETS.length
  const chars = CHAR_SETS[setIdx]
  const repeat = 2 + (cycle % 4) // 2-5 repeats = 6-15 chars
  const text = chars.repeat(repeat)

  try {
    editBufferInsertText(eb, text.substring(0, 12)) // limit to 12 chars
    if (cycle % 20 === 0) {
      fs.writeSync(2, `  stress ${cycle}/${STRESS_COUNT}: insertText("${text.substring(0, 12)}") OK\n`)
    }
  } catch (e) {
    fs.writeSync(2, `  STRESS PANIC at cycle ${cycle}: ${e.message}\n`)
    stressPanics++
    safetyPanic = true
  }
}

assert(stressPanics === 0, `stress: ${stressPanics} panics in ${STRESS_COUNT} cycles (expected 0)`)

// Also test with setCursor calls interleaved (like the Input component does)
header("Phase 4: Cursor motion + typing (Input component simulation)")
editBufferSetCursor(eb, 0, 0)

for (let cycle = 0; cycle < 50; cycle++) {
  try {
    editBufferInsertText(eb, "test")
    editBufferSetCursor(eb, 0, 0)
    editBufferInsertText(eb, "XYZ")
    if (cycle % 10 === 0) {
      fs.writeSync(2, `  cursor-motion cycle ${cycle}/50 OK\n`)
    }
  } catch (e) {
    fs.writeSync(2, `  CURSOR PANIC at cycle ${cycle}: ${e.message}\n`)
    stressPanics++
    safetyPanic = true
  }
}

// ============================================================
// Phase 5: Polling API functionality test
// ============================================================
header("Phase 5: Polling API smoke test")

// Disable events (so our test emits don't trigger callbacks)
disableEvents(false) // re-enable to allow bufferEvent to work

// Force setUsePolling to true (should already be default)
setUsePolling(true)

// Create an event sink and emit an event to check polling works
const createEventSink = lib.func("createEventSink", "void*", ["void*"])
const eventSink = createEventSink(null)
assert(eventSink !== null, "createEventSink returned non-null")

// Now check sigcatch crash log
header("Phase 6: Check sigcatch crash log")

const crashLogPath = (process.env.HOME || "/tmp") + "/opencode-crash.log"
if (fs.existsSync(crashLogPath)) {
  const contents = fs.readFileSync(crashLogPath, "utf8").trim()
  if (contents.length > 0) {
    fs.writeSync(2, `  CRASH LOG EXISTS: ${crashLogPath}\n`)
    fs.writeSync(2, `  Contents:\n${contents}\n`)
    // Only fail if crash log has actual crash data (not just headers)
    if (contents.includes("SIGSEGV") || contents.includes("fault_address")) {
      assert(false, "crash log contains SIGSEGV data — crash still occurs")
    }
  } else {
    assert(true, "crash log is empty — no crash detected")
  }
} else {
  fs.writeSync(2, "  INFO: no sigcatch crash log found — either handler wasn't triggered or wasn't installed\n")
}

// ============================================================
// Cleanup
// ============================================================
destroyEditBuffer(eb)
fs.writeSync(2, "\n")

// ============================================================
// Summary
// ============================================================
header("RESULTS")
fs.writeSync(2, `  Passed: ${pass}\n`)
fs.writeSync(2, `  Failed: ${fail}\n`)
fs.writeSync(2, `  Safety panics: ${safetyPanic ? "YES ⚠️  — ReleaseSafe caught something!" : "none ✅"}\n`)

if (safetyPanic) {
  fs.writeSync(2, "\n⚠️  ReleaseSafe detected a safety violation (panic). Check stderr output for file:line.\n")
  fs.writeSync(2, "  This is the root cause location. Report it for fixing.\n")
} else if (fail === 0) {
  fs.writeSync(2, "\n✅ All tests passed. ReleaseSafe built did NOT panic — crash mechanism is outside Zig safety checks.\n")
  fs.writeSync(2, "  Next step: test in production OpenCode app (typing in Input).\n")
} else {
  fs.writeSync(2, `\n⚠️  ${fail} test(s) failed. Review output above.\n`)
}

process.exit(fail > 0 ? 1 : 0)
